from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects describing a CelestialBody (or related person)
    into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a clause
    def clause(t: Triple) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object
        # Normalise predicate strings for easier handling
        p = pred.lower()
        if p == "discoverer":
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            return f"{subj} was discovered on {obj}"
        if p == "apoapsis":
            return f"{subj} has an apoapsis of {obj}"
        if p == "periapsis":
            return f"{subj} has a periapsis of {obj}"
        if p == "orbitalperiod":
            return f"{subj} orbits in {obj}"
        if p == "averagespeed":
            return f"{subj} travels at an average speed of {obj}"
        if p == "escapevelocity":
            return f"{subj} has an escape velocity of {obj}"
        if p == "mass":
            return f"{subj} has a mass of {obj}"
        if p in {"temperature", "maximumtemperature", "mintemperature", "minimumtemperature", "meantemperature"}:
            # handle temperature variants
            label = {
                "temperature": "a temperature of",
                "maximumtemperature": "a maximum temperature of",
                "minimumtemperature": "a minimum temperature of",
                "meantemperature": "a mean temperature of",
            }.get(p, "a temperature of")
            return f"{subj} has {label} {obj}"
        if p == "density":
            return f"{subj} has a density of {obj}"
        if p == "rotationperiod":
            return f"{subj} rotates every {obj}"
        if p == "formername":
            return f"{subj} was formerly known as {obj}"
        if p == "absolutemagnitude":
            return f"{subj} has an absolute magnitude of {obj}"
        if p == "surfacearea":
            return f"{subj} has a surface area of {obj}"
        if p == "deathcause":
            return f"{subj} died of {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            return f"{subj} was {obj}"
        if p == "stateoforigin":
            return f"{subj} originated from {obj}"
        if p == "almamater":
            return f"{subj} studied at {obj}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "doctoralstudent":
            return f"{subj} supervised {obj}"
        if p == "deathdate":
            return f"{subj} died on {obj}"
        if p == "birthdate":
            return f"{subj} was born on {obj}"
        # Default fallback
        return f"{subj} has {pred} {obj}"

    # Build clauses for all triples, preserving order
    clauses = [clause(t) for t in triples]

    # Join clauses into a single sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
    return sentence

# EVOLVE-BLOCK-END

